    <style>
        /* Custom white theme */
        .bg-snpmb { background-color: #ffffff; }
        .text-snpmb-gray { color: #64748b; }
        .btn-snpmb-blue { background-color: #2563eb; }
        .btn-snpmb-blue:hover { background-color: #1d4ed8; }
        .btn-snpmb-dark { background-color: #f8fafc; }
        .btn-snpmb-dark:hover { background-color: #f1f5f9; }

        /* Dark mode overrides */
        .dark .bg-snpmb { background-color: #171d2b; }
        .dark .text-snpmb-gray { color: #8e9aab; }
        .dark .btn-snpmb-blue { background-color: #3b82f6; } /* Standard Tailwind Blue 500 equivalent */
        .dark .btn-snpmb-blue:hover { background-color: #2563eb; }
        .dark .btn-snpmb-dark { background-color: #262c38; }
        .dark .btn-snpmb-dark:hover { background-color: #323a49; }
        
        /* Ensure dark mode text changes reliably */
        .dark { color: #ffffff !important; }
        .dark h1, .dark .title-text { color: #ffffff !important; }
        
        /* Fallback for missing tailwind classes */
        .title-text { color: #111827; }
        
        /* Foolproof responsive layout (bypassing tailwind cache issues) */
        .layout-wrapper {
            display: flex;
            flex-direction: column-reverse; /* Put 2nd child (Image) on top of 1st child (Text) in Mobile */
            gap: 3rem;
            align-items: center;
            width: 100%;
        }
        .layout-wrapper > div { width: 100%; }
        @media (min-width: 1024px) {
            .layout-wrapper {
                flex-direction: row; /* Normal row for Desktop: Text Left, Image Right */
                gap: 5rem;
                justify-content: space-between;
            }
            .layout-wrapper > div {
                flex: 1;
            }
        }
        
        /* Dark mode SVG line override */
        .dark svg#freepik_stories-college-admission [style*="fill: rgb(38, 50, 56)"] {
            fill: #cbd5e1 !important;
        }

        /* SVG Animation Styles */
        svg#freepik_stories-college-admission:not(.animated) .animable {opacity: 0;}
        svg#freepik_stories-college-admission.animated #freepik--Shadow--inject-81 {animation: 1s 1 forwards cubic-bezier(.36,-0.01,.5,1.38) slideRight;animation-delay: 0s;}
        svg#freepik_stories-college-admission.animated #freepik--Plant--inject-81 {animation: 1s 1 forwards cubic-bezier(.36,-0.01,.5,1.38) slideDown;animation-delay: 0s;}
        svg#freepik_stories-college-admission.animated #freepik--Letter--inject-81 {animation: 1s 1 forwards cubic-bezier(.36,-0.01,.5,1.38) zoomIn;animation-delay: 0s;}
        svg#freepik_stories-college-admission.animated #freepik--Confetti--inject-81 {animation: 1s 1 forwards cubic-bezier(.36,-0.01,.5,1.38) fadeIn;animation-delay: 0s;}
        svg#freepik_stories-college-admission.animated #freepik--Speech_Bubble--inject-81 {animation: 1s 1 forwards cubic-bezier(.36,-0.01,.5,1.38) slideUp;animation-delay: 0s;}
        svg#freepik_stories-college-admission.animated #freepik--Character_2--inject-81 {animation: 1s 1 forwards cubic-bezier(.36,-0.01,.5,1.38) slideRight;animation-delay: 0s;}
        svg#freepik_stories-college-admission.animated #freepik--Character_1--inject-81 {animation: 1s 1 forwards cubic-bezier(.36,-0.01,.5,1.38) slideUp;animation-delay: 0s;}

        @keyframes slideRight { 0% { opacity: 0; transform: translateX(30px); } 100% { opacity: 1; transform: translateX(0); } }
        @keyframes slideDown { 0% { opacity: 0; transform: translateY(-30px); } 100% { opacity: 1; transform: translateY(0); } }
        @keyframes zoomIn { 0% { opacity: 0; transform: scale(0.5); } 100% { opacity: 1; transform: scale(1); } }
        @keyframes fadeIn { 0% { opacity: 0; } 100% { opacity: 1; } }
        @keyframes slideUp { 0% { opacity: 0; transform: translateY(30px); } 100% { opacity: 1; transform: inherit; } }
    </style>
</head>

